import{_ as t,o as i,c as a,ag as n,ah as o}from"./chunks/framework.D9bIGSBm.js";const c=JSON.parse('{"title":"MCP 服务器","description":"","frontmatter":{},"headers":[],"relativePath":"settings/mcp.md","filePath":"settings/mcp.md"}'),e={name:"settings/mcp.md"};function r(l,s,d,h,p,g){return i(),a("div",null,[...s[0]||(s[0]=[n('<h1 id="mcp-服务器" tabindex="-1">MCP 服务器 <a class="header-anchor" href="#mcp-服务器" aria-label="Permalink to &quot;MCP 服务器&quot;">​</a></h1><p><strong>入口：</strong> 侧边栏 → <strong>设置</strong> → <strong>MCP 服务器</strong></p><p>MCP（Model Context Protocol，模型上下文协议）是让 AI 连接外部工具和数据源的开放协议。通过添加 MCP 服务器，Claude 或 Codex 可以在对话中直接调用数据库查询、文件系统、Web 搜索等能力。例如，接入文件系统类或数据库类的 MCP 服务器后，AI 就能直接读取相应数据来回答问题，而无需你手动把内容复制粘贴进对话。</p><p>本页管理 Claude CLI 与 Codex CLI 各自的 MCP 服务器配置。页面顶部的 <strong>Claude | Codex</strong> 切换栏用于分别维护各 CLI 的服务器列表。</p><p><img src="'+o+`" alt="MCP 服务器设置页面，顶部 Claude/Codex 切换栏，下方服务器列表每行显示状态灯、名称、作用域标签和传输协议摘要"></p><hr><h2 id="服务器列表" tabindex="-1">服务器列表 <a class="header-anchor" href="#服务器列表" aria-label="Permalink to &quot;服务器列表&quot;">​</a></h2><p>列表中每条服务器记录显示以下信息：</p><ul><li><strong>状态灯</strong> — 绿色表示已启用，暗色表示已停用</li><li><strong>名称</strong> — 服务器标识</li><li><strong>作用域标签</strong> — <strong>用户</strong>（蓝色，存储在用户级配置，跨工作区生效）或 <strong>工作区</strong>（绿色，仅对当前关联的工作区生效）</li><li><strong>传输协议摘要</strong> — 如 <code>stdio</code> 或服务端地址</li></ul><p>每行右侧提供三个操作：</p><ul><li>编辑按钮（铅笔图标）— 打开编辑表单</li><li>删除按钮（红色垃圾桶图标）— 删除服务器，不可撤销</li><li>启用开关 — 拨动即可即时启用或停用，无需重新填写配置</li></ul><blockquote><p>Claude 模式下若未关联工作区任务，启用开关不可操作，可先在任务列表中点击一个工作区任务再切换；Codex 模式无此限制。</p></blockquote><hr><h2 id="添加-mcp-服务器" tabindex="-1">添加 MCP 服务器 <a class="header-anchor" href="#添加-mcp-服务器" aria-label="Permalink to &quot;添加 MCP 服务器&quot;">​</a></h2><p>点击列表页顶部的 <strong>新建 MCP 服务器</strong> 按钮打开配置表单。表单支持两种编辑模式，通过顶部切换按钮选择：<strong>表单</strong>（逐字段填写）或 <strong>JSON</strong>（直接粘贴完整配置）。</p><h3 id="表单模式字段" tabindex="-1">表单模式字段 <a class="header-anchor" href="#表单模式字段" aria-label="Permalink to &quot;表单模式字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>作用域</strong></td><td>选择 <strong>用户</strong> 或 <strong>工作区</strong>；编辑现有服务器时作用域锁定，不可更改；未关联工作区时只能选 <strong>用户</strong></td></tr><tr><td><strong>名称</strong></td><td>服务器标识；创建后不可修改</td></tr><tr><td><strong>类型</strong></td><td>传输协议，见下表</td></tr></tbody></table><p><strong>类型选项：</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>stdio（本地命令）</strong></td><td>通过本地子进程通信，适合大多数本地工具</td></tr><tr><td><strong>HTTP (Streamable)</strong></td><td>连接支持 Streamable HTTP 的远程服务端</td></tr><tr><td><strong>SSE（Server-Sent Events）</strong></td><td>连接通过 SSE 推送消息的远程服务端</td></tr></tbody></table><blockquote><p>以上类型名称均为界面原文，其中「HTTP (Streamable)」在界面中即以英文括号显示。</p></blockquote><p><strong>stdio 类型额外字段：</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命令</strong></td><td>启动服务器的可执行文件，如 <code>npx</code></td></tr><tr><td><strong>参数（空格分隔）</strong></td><td>传递给命令的参数，如 <code>-y @modelcontextprotocol/server-memory</code></td></tr><tr><td><strong>环境变量（可选）</strong></td><td>JSON 对象，注入服务器子进程的环境变量，如 <code>{&quot;MY_API_KEY&quot;: &quot;your-key&quot;}</code></td></tr></tbody></table><p><strong>HTTP / SSE 类型额外字段：</strong></p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>URL</strong></td><td>服务端地址，如 <code>https://example.com/mcp</code></td></tr><tr><td><strong>请求头 Headers（可选）</strong></td><td>JSON 对象，附加到请求的 HTTP 头，如 <code>{&quot;Authorization&quot;: &quot;Bearer ...&quot;}</code></td></tr></tbody></table><h3 id="json-模式" tabindex="-1">JSON 模式 <a class="header-anchor" href="#json-模式" aria-label="Permalink to &quot;JSON 模式&quot;">​</a></h3><p>直接粘贴完整配置，支持两种格式：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;my-mcp-server&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;stdio&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>或带 <code>mcpServers</code> 外层键的格式（与 <code>claude_desktop_config.json</code> 兼容）：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;mcpServers&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;my-mcp-server&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;stdio&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;npx&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;args&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;-y&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@modelcontextprotocol/server-memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>填写完成后点击 <strong>添加</strong> 保存；编辑现有记录时按钮文案为 <strong>保存</strong>。点击 <strong>取消</strong> 或顶部 <strong>返回 MCP 列表</strong> 放弃变更。</p><details class="details custom-block"><summary>快速上手示例：4 步添加一个 stdio 服务器</summary><ol><li>点击 <strong>新建 MCP 服务器</strong>，<strong>作用域</strong> 选 <strong>用户</strong></li><li><strong>名称</strong> 填一个标识（如 <code>my-mcp-server</code>），<strong>类型</strong> 选 <strong>stdio（本地命令）</strong></li><li><strong>命令</strong> 填 <code>npx</code>，<strong>参数（空格分隔）</strong> 填 <code>-y @modelcontextprotocol/server-memory</code>（此处以 memory 服务器为例，实际按所用包的官方说明填写）</li><li>点击 <strong>添加</strong> 返回列表，确认该服务器状态灯为绿色（已启用），即可在对话中使用</li></ol></details><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>stdio 服务器启动失败</strong></p><ul><li>确认 <strong>命令</strong> 字段中的可执行文件已安装且在系统 <code>PATH</code> 中可找到</li><li>检查 <strong>参数</strong> 是否正确，例如使用 <code>npx</code> 时确认包名有效</li><li>若需要 API Key，请在 <strong>环境变量</strong> 字段以 JSON 格式填写，不要拼入命令字符串</li></ul><p><strong>HTTP / SSE 服务器无法连接</strong></p><ul><li>确认服务端地址可从本地网络访问</li><li>需要认证时请在 <strong>请求头 Headers</strong> 中填写 <code>Authorization</code> 等认证头</li></ul><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/docs/settings/plugins.html">插件</a> — 通过插件市场扩展 CLI 功能，安装第三方工具集</li><li><a href="/docs/settings/skills.html">技能</a> — 管理预置的专项工作流，在对话中通过 <code>/</code> 命令快速触发</li></ul>`,40)])])}const E=t(e,[["render",r]]);export{c as __pageData,E as default};
